class Recipe {
  String id, title, category, imagePath, difficulty, liquidNote;
  int minutes, servings, rating, temp;
  List<Ingredient> ingredients;
  List<CookingStep> steps;
  List<String> videos;
  bool favorite;
  Recipe({required this.id, required this.title, required this.category, this.imagePath='', this.difficulty='Facile', this.liquidNote='', this.minutes=30, this.servings=4, this.rating=5, this.temp=160, this.favorite=false, List<Ingredient>? ingredients, List<CookingStep>? steps, List<String>? videos}) : ingredients=ingredients??[], steps=steps??[], videos=videos??[];
  Map<String,dynamic> toJson()=>{'id':id,'title':title,'category':category,'imagePath':imagePath,'difficulty':difficulty,'liquidNote':liquidNote,'minutes':minutes,'servings':servings,'rating':rating,'temp':temp,'favorite':favorite,'ingredients':ingredients.map((e)=>e.toJson()).toList(),'steps':steps.map((e)=>e.toJson()).toList(),'videos':videos};
  factory Recipe.fromJson(Map<String,dynamic> j)=>Recipe(id:j['id'],title:j['title'],category:j['category'],imagePath:j['imagePath']??'',difficulty:j['difficulty']??'Facile',liquidNote:j['liquidNote']??'',minutes:j['minutes']??30,servings:j['servings']??4,rating:j['rating']??5,temp:j['temp']??160,favorite:j['favorite']??false,ingredients:(j['ingredients'] as List? ?? []).map((e)=>Ingredient.fromJson(e)).toList(),steps:(j['steps'] as List? ?? []).map((e)=>CookingStep.fromJson(e)).toList(),videos:List<String>.from(j['videos']??[]));
}
class Ingredient {String name, unit; double qty; bool have; Ingredient(this.name,this.qty,this.unit,{this.have=false}); Map<String,dynamic> toJson()=>{'name':name,'qty':qty,'unit':unit,'have':have}; factory Ingredient.fromJson(Map<String,dynamic> j)=>Ingredient(j['name'],(j['qty'] as num).toDouble(),j['unit'],have:j['have']??false);}
class CookingStep {String title,note; int minutes,temp; CookingStep(this.title,this.minutes,this.temp,this.note); Map<String,dynamic> toJson()=>{'title':title,'minutes':minutes,'temp':temp,'note':note}; factory CookingStep.fromJson(Map<String,dynamic> j)=>CookingStep(j['title'],j['minutes'],j['temp']??0,j['note']??'');}

class Store extends ChangeNotifier{
  List<Recipe> recipes=[];
  Future<void> load() async {final sp=await SharedPreferences.getInstance(); final raw=sp.getString('recipes'); if(raw==null){recipes=[sampleRecipe()]; await save();} else {recipes=(jsonDecode(raw) as List).map((e)=>Recipe.fromJson(e)).toList();} notifyListeners();}
  Future<void> save() async {final sp=await SharedPreferences.getInstance(); await sp.setString('recipes', jsonEncode(recipes.map((e)=>e.toJson()).toList())); notifyListeners();}
  void upsert(Recipe r){final i=recipes.indexWhere((e)=>e.id==r.id); if(i>=0){recipes[i]=r;}else{recipes.add(r);} save();}
  void delete(String id){recipes.removeWhere((e)=>e.id==id); save();}
}
Recipe sampleRecipe()=>Recipe(id:'r1',title:'Tajine Poulet aux Olives',category:'Tajines',minutes:45,servings:4,rating:5,temp:160,liquidNote:'0.7 L / environ 3 verres et demi',videos:['https://youtube.com'],ingredients:[Ingredient('Poulet fermier',1.5,'kg'),Ingredient('Olives vertes',1,'verre'),Ingredient('Oignons',2,'pièces'),Ingredient('Eau',0.7,'L'),Ingredient('Safran',1,'pincée')],steps:[CookingStep('Faire revenir le poulet dans l’huile d’olive',10,160,'Remuer et vérifier le feu'),CookingStep('Ajouter oignons, épices et eau',20,180,'Vérifier l’eau pour éviter que la sauce sèche'),CookingStep('Ajouter les olives et réduire le feu',15,120,'Baisser le feu au minimum')]);

