class CookingPage extends StatefulWidget{final Recipe recipe; const CookingPage({super.key,required this.recipe});@override State<CookingPage> createState()=>_CookingPageState();}
class _CookingPageState extends State<CookingPage>{int idx=0,remaining=0,total=1;Timer? timer;bool running=false;@override void initState(){super.initState();setStep();}void setStep(){final m=widget.recipe.steps.isEmpty?1:widget.recipe.steps[idx].minutes;remaining=m*60;total=remaining;}void start(){timer?.cancel();running=true;timer=Timer.periodic(const Duration(seconds:1),(t){if(remaining<=0){t.cancel();alarm();}else setState(()=>remaining--);});setState((){});}void pause(){timer?.cancel();setState(()=>running=false);}Future<void> alarm()async{running=false;await Vibration.vibrate(duration:1200);const details=NotificationDetails(android:AndroidNotificationDetails('alarm','Alarmes cuisson',importance:Importance.max,priority:Priority.high,playSound:true,enableVibration:true,fullScreenIntent:true));await notifications.show(99,'Temps écoulé !',widget.recipe.steps[idx].note,details);if(mounted)Navigator.push(context,MaterialPageRoute(builder:(_)=>AlarmScreen(note:widget.recipe.steps[idx].note,onMore:(){Navigator.pop(context);setState(()=>remaining=300);start();})));} @override void dispose(){timer?.cancel();super.dispose();}
  @override Widget build(BuildContext context){final step=widget.recipe.steps.isEmpty?CookingStep('Aucune étape',1,0,''):widget.recipe.steps[idx];final p=remaining/total;return Scaffold(body:SafeArea(child:Padding(padding:const EdgeInsets.all(24),child:Column(children:[Row(children:[roundIcon(Icons.arrow_back,()=>Navigator.pop(context)),const Spacer(),Text('Étape ${idx+1}/${widget.recipe.steps.length}',style:const TextStyle(fontWeight:FontWeight.w900))]),const SizedBox(height:30),CustomPaint(size:const Size(280,280),painter:RingPainter(p),child:SizedBox(width:280,height:280,child:Center(child:Text('${(remaining~/60).toString().padLeft(2,'0')}:${(remaining%60).toString().padLeft(2,'0')}',style:const TextStyle(fontSize:54,fontWeight:FontWeight.w300))))),const SizedBox(height:24),Text(step.title,textAlign:TextAlign.center,style:const TextStyle(fontSize:27,fontWeight:FontWeight.w900)),const SizedBox(height:10),card(Text('⚠ ${step.note}\n🌡 ${step.temp}°C',style:const TextStyle(fontSize:18,height:1.5,fontWeight:FontWeight.w700))),const Spacer(),Row(mainAxisAlignment:MainAxisAlignment.spaceEvenly,children:[circleBtn(running?Icons.pause:Icons.play_arrow,running?pause:start),circleBtn(Icons.stop,(){timer?.cancel();setStep();setState(()=>running=false);}),circleBtn(Icons.add,(){setState(()=>remaining+=300);})]),const SizedBox(height:16),bigButton('Étape suivante',(){timer?.cancel();if(idx<widget.recipe.steps.length-1){setState(()=>idx++);setStep();}else{Navigator.pop(context);}})]))));}}

