class HeroImage extends StatelessWidget{final Recipe r;final double height;final bool compact;final VoidCallback? onTap;const HeroImage({super.key,required this.r,this.height=170,this.compact=false,this.onTap});@override Widget build(BuildContext context)=>GestureDetector(onTap:onTap,child:Container(height:height,decoration:BoxDecoration(borderRadius:BorderRadius.circular(32),gradient:const LinearGradient(colors:[Color(0xFFFFF4CF),Color(0xFFE6F0E8)])),clipBehavior:Clip.antiAlias,child:r.imagePath.isNotEmpty?Image.file(File(r.imagePath),fit:BoxFit.cover):CustomPaint(painter:FoodPainter(),child:Center(child:Text(compact?'':r.title,textAlign:TextAlign.center,style:const TextStyle(color:AppColors.green,fontWeight:FontWeight.w900,fontSize:18))))));}
class FoodPainter extends CustomPainter{ @override void paint(Canvas c,Size s){final p=Paint()..color=Colors.white.withOpacity(.65);c.drawCircle(Offset(s.width*.5,s.height*.42),s.shortestSide*.22,p);p.color=AppColors.green;p.style=PaintingStyle.stroke;p.strokeWidth=5;c.drawCircle(Offset(s.width*.5,s.height*.42),s.shortestSide*.16,p);final tp=TextPainter(text:const TextSpan(text:'🥘',style:TextStyle(fontSize:42)),textDirection:TextDirection.ltr)..layout();tp.paint(c,Offset(s.width/2-tp.width/2,s.height*.42-tp.height/2));} @override bool shouldRepaint(covariant CustomPainter oldDelegate)=>false;}
class RingPainter extends CustomPainter{final double progress;RingPainter(this.progress);@override void paint(Canvas c,Size s){final center=Offset(s.width/2,s.height/2);final r=s.width/2-14;final base=Paint()..color=Colors.white..strokeWidth=18..style=PaintingStyle.stroke..strokeCap=StrokeCap.round;c.drawCircle(center,r,base);final p=Paint()..color=AppColors.gold..strokeWidth=18..style=PaintingStyle.stroke..strokeCap=StrokeCap.round;c.drawArc(Rect.fromCircle(center:center,radius:r),-1.57,6.28*progress,false,p);}@override bool shouldRepaint(covariant RingPainter oldDelegate)=>oldDelegate.progress!=progress;}

BoxDecoration softBox(double radius)=>BoxDecoration(color:Colors.white,borderRadius:BorderRadius.circular(radius),boxShadow:shadow());List<BoxShadow> shadow()=>[BoxShadow(color:Colors.black.withOpacity(.08),blurRadius:16,offset:const Offset(0,8))];Widget roundIcon(IconData i,VoidCallback on)=>InkWell(onTap:on,child:Container(width:62,height:62,decoration:softBox(24),child:Icon(i,color:AppColors.dark,size:28)));Widget pill(String t,Color bg,Color fg)=>Container(padding:const EdgeInsets.symmetric(horizontal:16,vertical:9),decoration:BoxDecoration(color:bg,borderRadius:BorderRadius.circular(20)),child:Text(t,style:TextStyle(color:fg,fontWeight:FontWeight.w900)));Widget metric(String a,String b)=>Expanded(child:Container(margin:const EdgeInsets.only(right:8),padding:const EdgeInsets.symmetric(vertical:15),decoration:BoxDecoration(color:AppColors.gold.withOpacity(.9),borderRadius:BorderRadius.circular(28)),child:Column(children:[Text(a),Text(b,textAlign:TextAlign.center,style:const TextStyle(fontWeight:FontWeight.w900,fontSize:16))])));Widget card(Widget child)=>Container(margin:const EdgeInsets.only(bottom:12),padding:const EdgeInsets.all(14),decoration:softBox(24),child:child);Widget bigButton(String t,VoidCallback on)=>ElevatedButton(onPressed:on,style:ElevatedButton.styleFrom(backgroundColor:AppColors.gold,foregroundColor:AppColors.dark,elevation:8,padding:const EdgeInsets.symmetric(vertical:18),shape:RoundedRectangleBorder(borderRadius:BorderRadius.circular(28))),child:Center(child:Text(t,style:const TextStyle(fontWeight:FontWeight.w900,fontSize:18))));Widget outlineButton(String t,VoidCallback on)=>OutlinedButton(onPressed:on,style:OutlinedButton.styleFrom(padding:const EdgeInsets.symmetric(vertical:16),shape:RoundedRectangleBorder(borderRadius:BorderRadius.circular(24))),child:Text(t,style:const TextStyle(fontWeight:FontWeight.w900,fontSize:17,color:AppColors.dark)));Widget title(String t)=>Padding(padding:const EdgeInsets.only(top:16,bottom:10),child:Text(t,style:const TextStyle(fontSize:30,fontWeight:FontWeight.w900,color:AppColors.dark)));Widget circleBtn(IconData i,VoidCallback on)=>InkWell(onTap:on,child:Container(width:72,height:72,decoration:softBox(36),child:Icon(i,size:34,color:AppColors.green)));String fmt(double n)=>n==n.roundToDouble()?n.toInt().toString():n.toString();
